window.HK_LC3 = {"q12": [{"n": 1, "part": 1, "q": "", "qko": "", "opts": ["A man is pouring a beverage.", "A man is grasping a spoon.", "A man is placing an order at a café.", "A man is stacking some cups."], "optko": ["한 남자가 음료를 따르고 있다.", "한 남자가 숟가락을 움켜잡고 있다.", "한 남자가 카페에서 주문을 하고 있다.", "한 남자가 몇몇의 컵들을 쌓고 있다."], "ans": 0, "audio": "Test03_01.mp3", "img": "hk_t3_q1.jpg"}, {"n": 2, "part": 1, "q": "", "qko": "", "opts": ["The man is removing headphones.", "The man is using a piece of equipment.", "A path is lined with large stones.", "A tree is being chopped down."], "optko": ["남자가 헤드폰을 벗고 있다.", "남자가 하나의 장비를 사용하고 있다.", "큰 돌들이 길을 따라 늘어서 있다.", "나무가 베어지고 있다."], "ans": 1, "audio": "Test03_02.mp3", "img": "hk_t3_q2.jpg"}, {"n": 3, "part": 1, "q": "", "qko": "", "opts": ["People are fishing in a stream.", "Some boots have been taken off.", "A dam has been built in a river.", "Some hikers are crossing a stream."], "optko": ["사람들이 하천에서 낚시를 하고 있다.", "몇몇 부츠들이 벗어져 있다.", "강에 댐이 지어져 있다.", "등산객들 몇 명이 하천을 건너고 있다."], "ans": 3, "audio": "Test03_03.mp3", "img": "hk_t3_q3.jpg"}, {"n": 4, "part": 1, "q": "", "qko": "", "opts": ["They are collecting some rocks.", "They are holding hands.", "They are strolling across a bridge.", "They are going in opposite directions."], "optko": ["그들은 돌을 모으고 있다.", "그들은 손을 잡고 있다.", "그들은 다리를 가로질러 산책하고 있다.", "그들은 반대 방향으로 가고 있다."], "ans": 1, "audio": "Test03_04.mp3", "img": "hk_t3_q4.jpg"}, {"n": 5, "part": 1, "q": "", "qko": "", "opts": ["Passengers are reviewing a digital board.", "A book has been stored in a pocket.", "The woman is taking a nap.", "A bag has been placed next to the woman."], "optko": ["탑승객들은 디지털 게시판을 확인하고 있다.", "책이 주머니에 보관되어 있다.", "여자가 낮잠을 자고 있다.", "가방이 여자 옆에 놓여 있다."], "ans": 3, "audio": "Test03_05.mp3", "img": "hk_t3_q5.jpg"}, {"n": 6, "part": 1, "q": "", "qko": "", "opts": ["A bike rack is mounted on the side of a wall.", "A flag is flying from a pole.", "A sign is posted near the road.", "A road passes between some houses."], "optko": ["자전거 고정대가 벽 한 쪽에 설치되어 있다.", "깃발이 장대에서 휘날리고 있다.", "표지판이 도로 근처에 게시되어 있다.", "도로가 몇몇 집들 사이를 지나간다."], "ans": 2, "audio": "Test03_06.mp3", "img": "hk_t3_q6.jpg"}, {"n": 7, "part": 2, "q": "When were these windows installed?", "qko": "이 창문들은 언제 설치되었나요?", "opts": ["About five years ago.", "I just installed a new operating system.", "At the back of the workroom."], "optko": ["약 5년 전이에요.", "저는 방금 새 운영 체제를 설치했어요.", "작업실 뒤에요."], "ans": 0, "audio": "Test03_07.mp3"}, {"n": 8, "part": 2, "q": "Where can I find a grocery store in this neighborhood?", "qko": "이 근처에서 식료품점을 어디에서 찾을 수 있나요?", "opts": ["She was a great neighbor.", "There's one, but it's closed now.", "I own a house down the block."], "optko": ["그녀는 정말 좋은 이웃이었어요.", "하나가 있는데, 지금은 문을 닫았어요.", "저는 이 블록 아래에 집을 소유하고 있어요."], "ans": 1, "audio": "Test03_08.mp3"}, {"n": 9, "part": 2, "q": "Has the elevator been fixed yet?", "qko": "엘리베이터가 이제 수리되었나요?", "opts": ["On the second floor.", "Next to the stairs.", "I used it this morning."], "optko": ["2층에요.", "계단 옆에서요.", "저는 오늘 아침에 그것을 사용했어요."], "ans": 2, "audio": "Test03_09.mp3"}, {"n": 10, "part": 2, "q": "Is the board meeting scheduled for Wednesday?", "qko": "이사회 회의가 수요일로 예정되어 있나요?", "opts": ["Some financial concerns.", "No, Tuesday.", "We'll meet with him too."], "optko": ["재정적인 우려 사항이요.", "아니요, 화요일이요.", "우리는 그와도 만날 거예요."], "ans": 1, "audio": "Test03_10.mp3"}, {"n": 11, "part": 2, "q": "What time should I make the reservation for?", "qko": "제가 몇 시로 예약을 해야 하나요?", "opts": ["Whenever we can get a table.", "With the restaurant manager.", "Through an online booking site."], "optko": ["우리가 자리를 예약할 수 있을 때 언제든지요.", "식당 관리자와 함께요.", "온라인 예약 사이트를 통해서요."], "ans": 0, "audio": "Test03_11.mp3"}, {"n": 12, "part": 2, "q": "Has the architectural firm hired by Mayor Li started the project?", "qko": "Li 시장에 의해 고용된 건축 회사는 프로젝트를 시작했나요?", "opts": ["My company is based in Florida.", "Yes, some upcoming elections.", "Work got underway on May 1."], "optko": ["제 회사는 플로리다에 기반을 두고 있어요.", "네, 다가오는 선거들이요.", "작업은 5월 1일에 시작했어요."], "ans": 2, "audio": "Test03_12.mp3"}, {"n": 13, "part": 2, "q": "Who still needs to submit a reimbursement form?", "qko": "누가 아직 상환 양식을 제출해야 하나요?", "opts": ["All the documents.", "Patrick will drop you off.", "No one that I know of."], "optko": ["모든 서류들이요.", "Patrick이 당신을 데려다 줄 거예요.", "제가 알기로는 아무도 없어요."], "ans": 2, "audio": "Test03_13.mp3"}, {"n": 14, "part": 2, "q": "Which article will be printed on the front page?", "qko": "어떤 기사가 앞면에 인쇄될까요?", "opts": ["I printed a new pattern.", "One of the longer ones.", "In Friday's issue."], "optko": ["저는 새로운 무늬를 인쇄했어요.", "더 긴 것들 중 하나요.", "금요일 발간호에요."], "ans": 1, "audio": "Test03_14.mp3"}, {"n": 15, "part": 2, "q": "Are many customers making use of our video streaming services?", "qko": "많은 고객들이 우리의 실시간 비디오 재생 서비스를 이용하고 있나요?", "opts": ["Far more than we expected.", "Personalized customer profiles.", "A link on the Web site."], "optko": ["우리가 예상했던 것보다 훨씬 많이요.", "맞춤 고객 프로필이요.", "웹사이트의 링크요."], "ans": 0, "audio": "Test03_15.mp3"}, {"n": 16, "part": 2, "q": "The sleeves of this coat are a bit too long for me.", "qko": "이 코트의 소매는 제게 너무 길어요.", "opts": ["Probably for an hour.", "A popular fabric.", "Our tailor can fix that."], "optko": ["아마 1시간 동안이요.", "인기 있는 직물이요.", "우리 재단사가 수선할 수 있어요."], "ans": 2, "audio": "Test03_16.mp3"}, {"n": 17, "part": 2, "q": "When is the most convenient afternoon for you to lead the software demonstrations?", "qko": "당신이 소프트웨어 시연을 이끌기에 가장 편한 오후는 언제인가요?", "opts": ["On our latest computer applications.", "It's important for us to talk to them.", "My schedule is actually fairly flexible."], "optko": ["우리의 최신 컴퓨터 애플리케이션에 대해서요.", "우리가 그들에게 말하는 것이 중요해요.", "제 일정은 사실 꽤 유연해요."], "ans": 2, "audio": "Test03_17.mp3"}, {"n": 18, "part": 2, "q": "Who's going to present the flowers to Ms. Ellis at the retirement party?", "qko": "은퇴 파티에서 누가 Ms. Ellis에게 꽃을 줄 건가요?", "opts": ["When is the gathering being held?", "A dozen, please.", "The first part of the movie."], "optko": ["모임이 언제 열리나요?", "12송이 주세요.", "영화의 전반부요."], "ans": 0, "audio": "Test03_18.mp3"}, {"n": 19, "part": 2, "q": "Shouldn't the instructions for logging in to the system be written out?", "qko": "시스템에 로그인하는 것에 대한 설명서가 작성되어야 하지 않나요?", "opts": ["One of our system engineers.", "That won't be necessary.", "Yes, guidelines for the gym."], "optko": ["우리의 시스템 기술자들 중 한 명이요.", "그럴 필요 없을 거예요.", "네, 체육관에 대한 지침이요."], "ans": 1, "audio": "Test03_19.mp3"}, {"n": 20, "part": 2, "q": "Should we hire a band for the banquet or use recorded music?", "qko": "연회를 위해 밴드를 고용해야 하나요, 아니면 녹음된 음악을 사용해야 하나요?", "opts": ["We're enjoying the buffet.", "A live show would be more entertaining.", "I used to play the piano."], "optko": ["우리는 뷔페를 즐기고 있어요.", "라이브 공연이 더 흥겨울 것 같아요.", "저는 피아노를 연주했었어요."], "ans": 1, "audio": "Test03_20.mp3"}, {"n": 21, "part": 2, "q": "Betsy Glenn has been asked to return to our headquarters for a follow-up interview.", "qko": "Betsy Glenn이 후속 인터뷰를 위해 본사로 돌아오도록 요청받았어요.", "opts": ["She seems like the most qualified applicant.", "Oh, come back whenever you'd like!", "I can't answer that question now."], "optko": ["그녀는 가장 적합한 지원자인 것 같아요.", "아, 당신이 돌아오고 싶을 때 언제든지 돌아오세요!", "저는 지금 그 질문에 대답할 수 없어요."], "ans": 0, "audio": "Test03_21.mp3"}, {"n": 22, "part": 2, "q": "Where are the stage props for tonight's play?", "qko": "오늘 밤의 연극을 위한 무대 도구들은 어디에 있나요?", "opts": ["From a theater in Lima.", "Have you met the lead actress?", "Check behind the curtain."], "optko": ["리마에 있는 극장으로부터요.", "당신은 주연 여배우를 만나보았나요?", "커튼 뒤를 확인해 보세요."], "ans": 2, "audio": "Test03_22.mp3"}, {"n": 23, "part": 2, "q": "What floor is Robby Bluth's office located on?", "qko": "Robby Bluth의 사무실은 몇 층에 위치해 있나요?", "opts": ["He works overtime most days.", "The floors were carpeted in June.", "There's a building directory on that wall."], "optko": ["그는 거의 매일 야근해요.", "그 층들은 6월에 카펫이 깔렸어요.", "저쪽의 벽에 건물 안내판이 있어요."], "ans": 2, "audio": "Test03_23.mp3"}, {"n": 24, "part": 2, "q": "A freelance illustrator drew the pictures for your children's book, right?", "qko": "프리랜서 삽화가가 당신의 아동용 도서의 그림을 그렸어요, 그렇죠?", "opts": ["No, I'm not a talented artist.", "Yes, for my most recent publication.", "Let me recommend a photographer."], "optko": ["아니요, 저는 재능 있는 예술가가 아니에요.", "네, 저의 가장 최근 출판물에 대해서요.", "제가 사진가를 추천해 드릴게요."], "ans": 1, "audio": "Test03_24.mp3"}, {"n": 25, "part": 2, "q": "Would you like a ticket for the 9 o'clock screening?", "qko": "9시 상영 티켓을 드릴까요?", "opts": ["That would be great.", "Passes to the local zoo.", "OK, I can show it to you."], "optko": ["그게 좋겠어요.", "지역 동물원의 입장권이요.", "좋아요, 제가 당신에게 그것을 보여드릴게요."], "ans": 0, "audio": "Test03_25.mp3"}, {"n": 26, "part": 2, "q": "How many people will attend the presentation today?", "qko": "오늘 발표에 몇 명의 사람들이 참석할 것인가요?", "opts": ["Sign the attendance sheet.", "Six in total.", "Tomorrow will be better."], "optko": ["출석부에 서명하세요.", "총 여섯 명이요.", "내일이 더 나을 거예요."], "ans": 1, "audio": "Test03_26.mp3"}, {"n": 27, "part": 2, "q": "Will the product developers require another deadline extension?", "qko": "제품 개발자들이 또 마감일 연장을 요구할까요?", "opts": ["Most of the merchandise.", "The other side is in good condition.", "I hope they won't."], "optko": ["상품의 대부분이요.", "다른 쪽은 상태가 좋아요.", "그들이 그러지 않았으면 좋겠네요."], "ans": 2, "audio": "Test03_27.mp3"}, {"n": 28, "part": 2, "q": "When is tomorrow's train to Bern supposed to depart?", "qko": "내일 베른행 기차는 언제 출발하기로 되어 있나요?", "opts": ["Emma has the itinerary.", "Yesterday at 2 o'clock.", "In the overhead compartment."], "optko": ["Emma가 일정표를 갖고 있어요.", "어제 2시에요.", "머리 위의 짐칸에요."], "ans": 0, "audio": "Test03_28.mp3"}, {"n": 29, "part": 2, "q": "Are staff expected to take part in the session on workplace communication?", "qko": "직원들은 직장 내 의사소통에 관한 교육에 참가하도록 요구되나요?", "opts": ["No, the machines weren't taken apart.", "Thanks again for leading the discussion on wages.", "Yes, the event is mandatory for all personnel."], "optko": ["아니요, 기계들은 분해되지 않았어요.", "임금에 관한 토론을 이끌어 주셔서 다시 한번 감사해요.", "네, 그 행사는 모든 직원에게 의무적이에요."], "ans": 2, "audio": "Test03_29.mp3"}, {"n": 30, "part": 2, "q": "Why do you want to avoid crossing Lower Town Bridge?", "qko": "당신은 왜 Lower Town 다리를 건너는 것을 피하고 싶어 하나요?", "opts": ["A radio broadcaster said it's congested.", "Because she wants to bring a suitcase.", "I agree. We'll do that."], "optko": ["라디오 방송 진행자가 그곳이 혼잡하다고 했어요.", "그녀가 여행 가방을 가져가고 싶어 하기 때문이에요.", "저도 동의해요. 그렇게 해요."], "ans": 0, "audio": "Test03_30.mp3"}, {"n": 31, "part": 2, "q": "Ben Graber can mount this television to the wall, can't he?", "qko": "Ben Graber는 벽에 이 텔레비전을 설치할 수 있죠, 그렇지 않나요?", "opts": ["Any amount you donate would be appreciated.", "You'll have to ask him directly.", "Isn't this the remote control for the device?"], "optko": ["당신이 얼마를 기부하시든 감사하겠습니다.", "당신은 그에게 직접 물어봐야 할 거예요.", "이것이 그 장치를 위한 리모컨 아닌가요?"], "ans": 1, "audio": "Test03_31.mp3"}], "sets34": [{"start": 32, "part": 3, "intro": "", "graphic": false, "speakers": "M-Ca / W-Am", "audio": "Test03_32-34.mp3", "qs": [{"n": 32, "q": "Where does the woman plan to travel?", "opts": ["To Mexico", "To Brazil", "To Canada", "To Switzerland"], "ans": 1, "ko": "여자는 어디로 여행을 갈 계획인가?"}, {"n": 33, "q": "What problem does the woman mention?", "opts": ["Her reimbursement request was denied.", "A product needs to be repaired.", "Her trip has been postponed.", "A service is expensive."], "ans": 3, "ko": "여자는 무슨 문제를 언급하는가?"}, {"n": 34, "q": "What will the woman most likely do this evening?", "opts": ["Visit a business", "Cancel a contract", "Update an itinerary", "Pay a bill"], "ans": 0, "ko": "여자는 오늘 저녁에 무엇을 할 것 같은가?"}], "script": [{"sp": "M", "en": "Louisa, I heard you're taking a vacation in Mexico this summer.", "ko": "Louisa, 저는 당신이 이번 여름에 멕시코에서 휴가를 보낼 거라고 들었어요."}, {"sp": "W", "en": "Brazil, actually . . . I'm really looking forward to it, but I could use your advice about something related to my trip.", "ko": "사실, 브라질이에요… 저는 정말 기대하고 있는데, 제 여행과 관련한 어떤 부분에 대해 당신의 조언을 활용할 수 있을 것 같아요."}, {"sp": "M", "en": "Sure. How can I help?", "ko": "물론이죠, 어떻게 도와드릴까요?"}, {"sp": "W", "en": "Well, the mobile company I use charges high fees for data usage outside of Canada. You mentioned a while back that your phone bill was reasonable after you traveled to France. Who is your service provider?", "ko": "음, 제가 이용하는 통신 회사는 캐나다 밖에서 발생하는 데이터 사용에 대해 높은 요금을 부과해요. 당신은 얼마 전에 프랑스에 여행 다녀온 후에 휴대 전화 청구서가 적정하다고 말했었잖아요. 당신의 서비스 제공업체는 어디인가요?"}, {"sp": "M", "en": "Pacific Mobile. They have several packages with very reasonable rates if you sign a one-year contract.", "ko": "Pacific Mobile이요. 만약 당신이 1년 계약을 맺으면 매우 합리적인 요금의 패키지가 여러 개 있어요."}, {"sp": "W", "en": "Great. I'll stop by a Pacific Mobile branch this evening and look into that.", "ko": "아주 좋네요. 오늘 저녁에 Pacific Mobile 지점에 들러서 그걸 알아봐야겠어요."}]}, {"start": 35, "part": 3, "intro": "", "graphic": false, "speakers": "M-Au / W-Br", "audio": "Test03_35-37.mp3", "qs": [{"n": 35, "q": "Why does the man need a permit?", "opts": ["He bought a car last month.", "He was informed about a policy change.", "He lives near a subway station.", "He moved into a new residence."], "ans": 3, "ko": "남자는 왜 허가증이 필요한가?"}, {"n": 36, "q": "Who is Mr. Hong?", "opts": ["A building manager", "A department head", "A corporate shareholder", "A company president"], "ans": 1, "ko": "Mr. Hong은 누구인가?"}, {"n": 37, "q": "According to the woman, what are staff prohibited from doing?", "opts": ["Taking unauthorized breaks", "Parking in certain spots", "Using a pass for multiple cars", "Contacting clients directly"], "ans": 1, "ko": "여자에 따르면, 직원들은 무엇을 하는 것이 금지되는가?"}], "script": [{"sp": "M", "en": "I need to request an employee parking permit. My new apartment isn't near a subway station, so I will have to drive to work from now on.", "ko": "저는 직원 주차 허가증을 요청해야 해요. 저의 새 아파트는 지하철역 근처가 아니라서 이제부터 회사까지 운전을 해야만 할 거예요."}, {"sp": "W", "en": "You should contact the human resources manager, Mr. Hong. Just note that when I asked him about getting one last month, I was told that there is a waiting list.", "ko": "당신은 인사 부장인 Mr. Hong에게 연락해야 해요. 다만 제가 지난달에 그것을 받는 것에 대해 그에게 문의했을 때, 대기자 목록이 있다고 들었다는 것만 알아두세요."}, {"sp": "M", "en": "Really? The lot in front of our building is never full, though.", "ko": "정말이요? 하지만 저희 건물 앞의 주차장은 가득 찬 적이 없잖아요."}, {"sp": "W", "en": "I guess the company needs to ensure that our clients can find a place to park. So, staff aren't allowed to park in the front two rows.", "ko": "회사는 우리의 고객들이 주차할 공간을 찾을 수 있도록 확실히 해야 하는 것 같아요. 그래서 직원들은 앞의 두 열에 주차하도록 허용되지 않아요."}, {"sp": "M", "en": "Hmm . . . Do you know Mr. Hong's extension? I'll speak to him about this situation now.", "ko": "흠… Mr. Hong의 내선 번호를 아시나요? 이 상황에 대해 지금 그와 이야기해 볼게요."}]}, {"start": 38, "part": 3, "intro": "", "graphic": false, "speakers": "M-Au / W-Am", "audio": "Test03_38-40.mp3", "qs": [{"n": 38, "q": "What is Shannon in charge of?", "opts": ["Negotiating a payment", "Scheduling a repair", "Filling an order", "Reviewing a process"], "ans": 0, "ko": "Shannon은 무엇을 담당하는가?"}, {"n": 39, "q": "What does the woman mean when she says, \"Three other employees were just added to her team\"?", "opts": ["A project will get started soon.", "A manager has approved a request.", "A company decided to hire more staff.", "A coworker has sufficient help."], "ans": 3, "ko": "여자는 \"세 명의 다른 직원들이 막 그녀의 팀에 투입되었어요\"라고 말할 때 무엇을 의도하는가?"}, {"n": 40, "q": "When must an agreement be finalized?", "opts": ["By June 2", "By June 4", "By June 6", "By June 8"], "ans": 3, "ko": "계약은 언제 마무리되어야 하는가?"}], "script": [{"sp": "M", "en": "Cathy, how are the pay rate negotiations for our contract with Sutton Technical Consulting going?", "ko": "Cathy, Sutton 기술 컨설팅사와의 계약에 대한 임금 협상은 어떻게 되어가나요?"}, {"sp": "W", "en": "Shannon is in charge of that, actually. She mentioned that it hasn't been a smooth process.", "ko": "사실, 그건 Shannon이 담당하고 있어요. 그녀는 그것이 순조로운 과정이 아니라고 말했어요."}, {"sp": "M", "en": "That's unfortunate. Maybe we should check if she needs our assistance. I heard that our manager wants to review the contract on June 2. That's just four days away.", "ko": "안타깝네요. 혹시 그녀가 우리의 도움이 필요한지 확인해 봐야겠어요. 관리자가 6월 2일에 계약을 검토하길 원한다고 들었어요. 그건 바로 4일 뒤잖아요."}, {"sp": "W", "en": "Three other employees were just added to her team. Plus, the deadline has been pushed back to June 8.", "ko": "세 명의 다른 직원들이 막 그녀의 팀에 투입되었어요. 게다가, 마감일이 6월 8일로 미뤄졌어요."}, {"sp": "M", "en": "That's great. She'll have plenty of time to finalize the contract, then.", "ko": "잘됐네요. 그럼 그녀가 계약을 마무리 지을 충분한 시간이 있겠어요."}]}, {"start": 41, "part": 3, "intro": "", "graphic": false, "speakers": "M-Ca / W-Br", "audio": "Test03_41-43.mp3", "qs": [{"n": 41, "q": "What does the man ask about?", "opts": ["Where a bus is boarding", "Why a departure was delayed", "Whether a vehicle has left", "When a station will close"], "ans": 2, "ko": "남자는 무엇에 관해 문의하는가?"}, {"n": 42, "q": "What time will the man most likely arrive in Oakville?", "opts": ["At 2:30 P.M.", "At 4:30 P.M.", "At 6:00 P.M.", "At 7:00 P.M."], "ans": 2, "ko": "남자는 Oakville에 몇 시에 도착할 것 같은가?"}, {"n": 43, "q": "What will the man receive?", "opts": ["A fare reduction", "A travel voucher", "A seat upgrade", "A partial refund"], "ans": 0, "ko": "남자는 무엇을 받을 것인가?"}], "script": [{"sp": "M", "en": "Excuse me. I'm supposed to take the 2:30 P.M. bus to Oakville. I'm a little late, and I'm wondering if it departed already.", "ko": "실례합니다. 저는 Oakville행 오후 2시 30분 버스를 타기로 되어 있어요. 제가 조금 늦었는데, 이미 버스가 출발했는지 궁금해요."}, {"sp": "W", "en": "Unfortunately, yes. The next bus going there departs at 4:30 P.M. It will arrive at the destination at 6:00 P.M.", "ko": "안타깝게도, 출발했어요. 그곳으로 가는 다음 버스는 오후 4시 30분에 출발합니다. 오후 6시에 목적지에 도착할 거예요."}, {"sp": "M", "en": "Hmm . . . I'm supposed to meet a friend in Oakville at 7:00 P.M., so that should be fine. I'll buy a ticket now, please.", "ko": "흠… 저는 Oakville에서 오후 7시에 친구를 만나기로 해서, 그건 괜찮을 거예요. 지금 티켓 하나를 살게요."}, {"sp": "W", "en": "Sure. Ordinarily, it would cost $60. But we have a special going on this week to mark our company's anniversary. So, your total will be $45.", "ko": "그럼요. 보통, 이것은 60달러예요. 하지만 이번 주에 회사의 기념일을 축하하기 위해 특별 할인이 진행되고 있어요. 따라서, 고객님의 총액은 45달러가 될 거예요."}]}, {"start": 44, "part": 3, "intro": "", "graphic": false, "speakers": "M-Au / W-Br", "audio": "Test03_44-46.mp3", "qs": [{"n": 44, "q": "What problem does the man mention?", "opts": ["A sign has been taken down.", "A delivery has been delayed.", "An appliance is malfunctioning.", "A staff member is absent."], "ans": 2, "ko": "남자는 무슨 문제를 언급하는가?"}, {"n": 45, "q": "Why does the woman say, \"An inspection of our fire sprinkler system was scheduled\"?", "opts": ["To apologize for a mistake", "To agree with a colleague", "To draw attention to a complaint", "To provide a reason for delay"], "ans": 3, "ko": "여자는 왜 \"화재 스프링클러 시스템에 관한 점검이 예정되어 있었어요\"라고 말하는가?"}, {"n": 46, "q": "What does the man ask the woman to do?", "opts": ["Set up an appointment", "Empty out a refrigerator", "Check a schedule online", "Test a sprinkler system"], "ans": 0, "ko": "남자는 여자에게 무엇을 하라고 요청하는가?"}], "script": [{"sp": "M", "en": "I was just in the break room, and there's a sign on the refrigerator saying that it still isn't working.", "ko": "제가 방금 휴게실에 있었는데, 냉장고에 여전히 작동하지 않는다는 표시가 있어요."}, {"sp": "W", "en": "I know. Several staff members have complained about it already.", "ko": "알아요. 여러 직원들이 이미 그것에 대해 불평했어요."}, {"sp": "M", "en": "I thought a technician was supposed to repair it last night—after the office closed.", "ko": "저는 어젯밤에 사무실 문이 닫힌 후 기술자가 이걸 수리하기로 한 줄 알았어요."}, {"sp": "W", "en": "An inspection of our fire sprinkler system was scheduled. Maybe today will work instead.", "ko": "화재 스프링클러 시스템에 관한 점검이 예정되어 있었어요. 아마 대신 오늘은 가능할 거예요."}, {"sp": "M", "en": "Hopefully, because we need to have it fixed as soon as possible. Why don't you call the repairperson now? See if you can arrange for him to visit our office this afternoon.", "ko": "이걸 가능한 한 빨리 수리해야 하기 때문에 그러길 바라요. 당신이 지금 수리공에게 전화하는 게 어떨까요? 오늘 오후에 그가 사무실을 방문할 수 있도록 준비할 수 있는지 확인해주세요."}]}, {"start": 47, "part": 3, "intro": "", "graphic": false, "speakers": "W-Am / M-Ca", "audio": "Test03_47-49.mp3", "qs": [{"n": 47, "q": "What problem does the man mention?", "opts": ["He was charged the wrong amount.", "He did not select the right product.", "He did not provide the correct information.", "He was given inaccurate instructions."], "ans": 2, "ko": "남자는 무슨 문제를 언급하는가?"}, {"n": 48, "q": "What does the woman ask for?", "opts": ["An identification card", "An application form", "A business address", "A tracking number"], "ans": 3, "ko": "여자는 무엇을 요청하는가?"}, {"n": 49, "q": "What does the woman say the man must do?", "opts": ["Have a package properly weighed", "Send a message to a friend", "Visit a post office Web site", "Wait for a parcel to be sent back"], "ans": 3, "ko": "여자는 남자가 무엇을 해야 한다고 말하는가?"}], "script": [{"sp": "W", "en": "Hello. Thank you for visiting Westford Post Office. How can I help you?", "ko": "안녕하세요. Westford 우체국을 방문해 주셔서 감사합니다. 어떻게 도와드릴까요?"}, {"sp": "M", "en": "About a week ago, my friend mailed me a package with some books. But I just realized that I gave him my old address. Now I'm worried I won't receive the package.", "ko": "일주일 정도 전에, 제 친구가 저에게 책이 들어 있는 소포를 보냈어요. 하지만 제가 그에게 저의 예전 주소를 주었다는 걸 막 깨달았어요. 이제 그 소포를 받지 못할 것 같아 걱정되네요."}, {"sp": "W", "en": "Well, do you have the item's tracking number? I can use it to look the package up in our system and see whether it's been delivered yet. If not, I can halt the shipment.", "ko": "음, 그 물품의 추적 번호를 갖고 계신가요? 제가 그걸 이용해서 저희 시스템 내에서 소포를 찾아보고 이미 발송되었는지 확인할 수 있어요. 안 되었으면, 배송을 중단해드릴게요."}, {"sp": "M", "en": "No, I don't have that.", "ko": "아니요, 저는 그걸 갖고 있지 않아요."}, {"sp": "W", "en": "In that case, you'll have to wait for the package to be returned to the sender. Your friend will have to mail it out again to the proper address. Sorry.", "ko": "그렇다면, 당신은 발송인에게 소포가 되돌아가도록 기다리셔야 할 거예요. 친구 분이 알맞은 주소로 그것을 다시 보내셔야 할 거고요. 죄송합니다."}]}, {"start": 50, "part": 3, "intro": "", "graphic": false, "speakers": "M-Au / W1-Br / W2-Am", "audio": "Test03_50-52.mp3", "qs": [{"n": 50, "q": "What most likely is the man's job?", "opts": ["Fitness instructor", "Delivery person", "Interior decorator", "Sales associate"], "ans": 3, "ko": "남자의 직업은 무엇인 것 같은가?"}, {"n": 51, "q": "What does the man say about the EZ Keep?", "opts": ["It is recommended by an expert.", "It works using a remote control.", "It is exclusively available online.", "It comes with free accessories."], "ans": 1, "ko": "남자는 EZ Keep에 관해 무엇을 말하는가?"}, {"n": 52, "q": "What will the man probably do next?", "opts": ["Contact another branch", "Compare some items", "Show a product", "Look up a price"], "ans": 2, "ko": "남자는 다음에 무엇을 할 것 같은가?"}], "script": [{"sp": "M", "en": "Welcome to Home Land Retail. How can I help you?", "ko": "Home Land 소매점에 오신 것을 환영합니다. 어떻게 도와드릴까요?"}, {"sp": "W1", "en": "We need shelves to store some extra equipment at our gym.", "ko": "저희는 체육관에서 여분의 장비를 보관할 선반들이 필요해요."}, {"sp": "M", "en": "I'd recommend the EZ Keep storage system. It's a rack that can be lowered to the floor, loaded, and then raised up to seven feet high. It's operated with a remote control.", "ko": "저는 EZ Keep 보관 장치를 추천해 드려요. 이것은 바닥까지 낮출 수 있고, 짐을 적재한 후 7피트 높이까지 올릴 수 있는 선반입니다. 리모컨으로 작동이 돼요."}, {"sp": "W2", "en": "Sounds perfect. What's the price?", "ko": "완벽한 것 같군요. 가격은 어떻게 되나요?"}, {"sp": "M", "en": "$800. Plus, we can ship it directly to your address.", "ko": "800달러입니다. 게다가, 저희는 고객님의 주소로 곧장 이걸 배송해 드릴 수 있어요."}, {"sp": "W1", "en": "Could the item be delivered within the next two weeks?", "ko": "앞으로 2주 이내에 물품이 배송될 수 있나요?"}, {"sp": "W2", "en": "Yeah, we want to organize the equipment before a promotional event we're running.", "ko": "네, 저희는 저희가 진행하는 판촉 행사 전에 장비를 준비하기를 원해요."}, {"sp": "M", "en": "All of our products are shipped in less than a week. Why don't we head over to the aisle with the storage racks now so that you can look at the EZ Keep?", "ko": "저희의 모든 제품은 1주 이내에 배송됩니다. 고객님들께서 EZ Keep을 살펴보실 수 있도록 지금 저장 선반들이 있는 통로로 가는 게 어떨까요?"}]}, {"start": 53, "part": 3, "intro": "", "graphic": false, "speakers": "M-Cn / W-Am", "audio": "Test03_53-55.mp3", "qs": [{"n": 53, "q": "What does the man say about his flight?", "opts": ["It includes a stopover.", "It is going to be delayed by an hour.", "It is fully booked.", "It will depart in the afternoon."], "ans": 3, "ko": "남자는 그의 비행편에 관해 무엇을 말하는가?"}, {"n": 54, "q": "Why are the speakers going to San Jose?", "opts": ["To review a hotel", "To take part in a session", "To inspect an office", "To do some sightseeing"], "ans": 1, "ko": "화자들은 왜 산호세에 가는가?"}, {"n": 55, "q": "What does the woman suggest?", "opts": ["Arranging a wake-up call", "Speaking to a front desk clerk", "Meeting in the lobby", "Moving to another hotel"], "ans": 2, "ko": "여자는 무엇을 제안하는가?"}], "script": [{"sp": "M", "en": "I'm taking an afternoon flight to San Jose on Tuesday to attend the seminar on facility safety that we signed up for. When will you be traveling?", "ko": "저는 우리가 신청한 시설 안전에 관한 세미나에 참석하기 위해 화요일에 산호세행 오후 비행기를 타요. 당신은 언제 가시나요?"}, {"sp": "W", "en": "I'm scheduled to complete an inspection at our Tucson factory that day, so I'll be leaving later in the evening. I plan on staying at the Surfside Inn near the downtown area.", "ko": "저는 그날 우리의 투손 공장에서 점검을 완료하기로 일정이 잡혀 있어서, 저녁 늦게 떠날 거예요. 저는 시내 가까이에 있는 Surfside 호텔에 묵을 계획이고요."}, {"sp": "M", "en": "Oh, that's my hotel too! Let's have an early breakfast on Wednesday morning and drive to the workshop together . . . umm . . . if that's OK with you.", "ko": "아, 그건 제가 묵는 호텔이기도 해요! 수요일 아침에 이른 아침 식사를 하고 워크숍에 같이 차를 타고 가요… 음… 당신이 그래도 괜찮다면요."}, {"sp": "W", "en": "I was just going to say that. Let's meet in the lobby at 6:15 A.M.", "ko": "제가 막 그 얘기를 하려고 했어요. 오전 6시 15분에 로비에서 만나요."}]}, {"start": 56, "part": 3, "intro": "", "graphic": false, "speakers": "W-Am / M-Cn", "audio": "Test03_56-58.mp3", "qs": [{"n": 56, "q": "What does the woman ask the man to do?", "opts": ["Clean out an office", "Install some devices", "Read some instructions", "Train a coworker"], "ans": 1, "ko": "여자는 남자에게 무엇을 하라고 요청하는가?"}, {"n": 57, "q": "What department will the new employees most likely work in?", "opts": ["Accounting", "Marketing", "Human resources", "Information technology"], "ans": 0, "ko": "새로운 직원들은 어떤 부서에서 일할 것 같은가?"}, {"n": 58, "q": "What will the man probably do next?", "opts": ["Visit a colleague", "Unload a package", "Return a shipment", "Assist an intern"], "ans": 0, "ko": "남자는 다음에 무엇을 할 것 같은가?"}], "script": [{"sp": "W", "en": "Rick, I got a request from the human resources department to set up computers for two new accountants that will be joining the firm on Friday. They'll be sharing the empty office on the second floor. I'd like you and Donna to take care of this today, please.", "ko": "Rick, 저는 인사부로부터 금요일에 입사하는 두 명의 새로운 회계사를 위해 컴퓨터들을 설치해달라는 요청을 받았어요. 그들은 2층에 있는 빈 사무실을 공유할 거예요. 당신과 Donna가 오늘 이걸 처리해 주었으면 좋겠어요."}, {"sp": "M", "en": "Sure. Should I use the spare computers that are currently in the storage area?", "ko": "물론이죠. 현재 창고에 있는 여분의 컴퓨터들을 사용해야 하나요?"}, {"sp": "W", "en": "No. We just received a shipment of new devices this morning. The boxes are in the main hallway.", "ko": "아니요, 우리는 오늘 아침에 막 새 기기들을 배송받았어요. 상자들은 본관 복도에 있어요."}, {"sp": "M", "en": "OK. I'll stop by Donna's workspace first to tell her about this task. Then, we'll take care of everything.", "ko": "알겠습니다. 먼저 Donna의 자리에 들러서 이 업무에 대해 그녀에게 말할게요. 그 다음에 저희가 모든 걸 처리할게요."}]}, {"start": 59, "part": 3, "intro": "", "graphic": false, "speakers": "M-Cn / W-Br", "audio": "Test03_59-61.mp3", "qs": [{"n": 59, "q": "Where most likely are the speakers?", "opts": ["In a classroom", "In a bookstore", "In a library", "In an auditorium"], "ans": 2, "ko": "화자들은 어디에 있는 것 같은가?"}, {"n": 60, "q": "What is mentioned about Forgotten Time?", "opts": ["It is currently unavailable.", "It was sold at discount.", "It was recently published.", "It is set in Seattle."], "ans": 2, "ko": "Forgotten Time에 관해 무엇이 언급되는가?"}, {"n": 61, "q": "What does the woman offer to do?", "opts": ["Process a return", "Extend a loan", "Cancel a payment", "Reprint a receipt"], "ans": 1, "ko": "여자는 무엇을 해주겠다고 제안하는가?"}], "script": [{"sp": "M", "en": "Excuse me. Can you see if I still have any books checked out? I don't think I do, but I'm not certain. My account is under the name David Harris.", "ko": "실례합니다. 제가 아직 대출 중인 책이 있는지 확인해 주실 수 있나요? 저는 있다고 생각하지 않는데, 확실하지 않아서요. 제 계정은 David Harris라는 이름으로 있어요."}, {"sp": "W", "en": "Just a minute . . . Well, it looks like you still have a novel by Brad Thompson called, uh, Forgotten Time. It was released just last month.", "ko": "잠시만요… 음, 당신은 아직 Brad Thompson의, 어, Forgotten Time이라고 불리는 소설책을 갖고 있는 것 같네요. 이건 지난달에 막 출간되었어요."}, {"sp": "M", "en": "Oh, right. I forgot about that one. I'll be visiting my family in Tacoma for a few days, so I'll drop it off next week.", "ko": "아, 맞아요. 제가 그것에 대해 잊었군요. 저는 며칠 동안 타코마에 있는 가족을 방문할 거라서 그것을 다음 주에 반납할게요."}, {"sp": "W", "en": "OK, but it's due tomorrow, which means you'll have to pay a late fee if you bring it back then. I can renew it now, if you'd like.", "ko": "네, 하지만 이건 내일 만기가 되고, 이것은 당신이 그때 책을 가져오면 연체료를 내야 할 거라는 것을 의미해요. 당신이 원하신다면, 제가 지금 기한을 연장해 드릴 수 있어요."}, {"sp": "M", "en": "I'd appreciate that.", "ko": "감사합니다."}]}, {"start": 62, "part": 3, "intro": "", "graphic": true, "speakers": "M-Cn / W-Br", "audio": "Test03_62-64.mp3", "qs": [{"n": 62, "q": "According to the woman, what should be shared with staff?", "opts": ["A password to an account", "Samples of merchandise", "A key to a storage room", "Copies of a document"], "ans": 3, "ko": "여자에 따르면, 직원들과 무엇이 공유되어야 하는가?"}, {"n": 63, "q": "Why does the man apologize?", "opts": ["He failed to respond to a message.", "He misplaced some lists.", "He misunderstood directions.", "He forgot about an appointment."], "ans": 2, "ko": "남자는 왜 사과하는가?"}, {"n": 64, "q": "Look at the graphic. Which size should the man reorder?", "opts": ["Extra small", "Small", "Medium", "Large"], "ans": 2, "ko": "시각 자료를 보시오. 남자는 어떤 사이즈를 추가 주문해야 하는가?"}], "script": [{"sp": "M", "en": "Ms. Williams, you wanted to talk to me?", "ko": "Ms. Williams, 제게 하실 말씀이 있으시다고요?"}, {"sp": "W", "en": "Yes, Ryan. Have you been sharing copies of the inventory lists with all the stock room staff like I asked?", "ko": "네, Ryan. 제가 요청한 것과 같이 모든 재고실 직원들과 재고 목록 사본을 공유하셨나요?"}, {"sp": "M", "en": "No, I thought you wanted me to give the lists to the store manager only. Sorry if I misunderstood your instructions.", "ko": "아니요, 저는 당신이 점포 관리자에게만 목록을 주길 원하신다고 생각했어요. 제가 당신의 지시를 잘못 이해했다면 죄송합니다."}, {"sp": "W", "en": "That's all right. But, please do that for future deliveries.", "ko": "괜찮습니다. 하지만, 앞으로의 배송에 대해서는 꼭 그렇게 해 주세요."}, {"sp": "M", "en": "Certainly. Is there anything else?", "ko": "물론입니다. 이외에 다른 것이 또 있으신가요?"}, {"sp": "W", "en": "Yeah. I need you to order more inventory for our shop. Anything with fewer than 10 items in stock, aside from extra small sizes. They don't sell as quickly, so we only need to keep five of those products on hand at a time.", "ko": "네. 우리 상점에 재고를 더 주문해 주셨으면 좋겠어요. 매우 작은 사이즈를 제외한 재고가 10개 이하인 품목은 어떤 것이든지요. 그것들은 빨리 팔리지 않으니까, 한 번에 다섯 개 제품들만 수중에 갖고 있으면 돼요."}, {"sp": "M", "en": "Right away, Ms. Williams.", "ko": "바로 할게요, Ms. Williams."}], "gimg": "hk_t3_g62.jpg"}, {"start": 65, "part": 3, "intro": "", "graphic": true, "speakers": "M, W", "audio": "Test03_65-67.mp3", "qs": [{"n": 65, "q": "What is mentioned about the woman?", "opts": ["She is an experienced employee.", "She must travel tomorrow.", "She works at an airport.", "She plans to stay at a hotel."], "ans": 0, "ko": "여자에 관해 무엇이 언급되는가? (A) 그녀는 경험이 풍부한 직원이다. (B) 그녀는 내일 이동해야 한다. (C) 그녀는 공항에서 근무한다. (D) 그녀는 호텔에 머무를 계획이다."}, {"n": 66, "q": "What information does the woman ask about?", "opts": ["A flight time", "An airline name", "A terminal number", "A departure gate"], "ans": 2, "ko": "여자는 무슨 정보에 관해 문의하는가? (A) 비행 시간 (B) 항공사 이름 (C) 터미널 번호 (D) 출발 탑승구"}, {"n": 67, "q": "Look at the graphic. Which route is the woman going to take?", "opts": ["Dale Street", "Lily Street", "Pine Street", "Red Street"], "ans": 3, "ko": "시각 자료를 보시오. 여자는 어떤 경로를 이용할 것인가? (A) Dale가 (B) Lily가 (C) Pine가 (D) Red가"}], "script": [{"sp": "M", "en": "Sabrina, our hotel will be hosting a VIP guest for the next week. His name is Mr. Graystone, and he's going to arrive at the airport at 3 P.M. today. I'd like you to go pick him up, since you're a veteran driver.", "ko": "Sabrina, 우리 호텔은 다음 주에 VIP 손님을 접대할 거예요. 그의 이름은 Mr. Graystone이고, 그가 오늘 오후 3시에 공항에 도착할 예정이에요. 당신이 경험이 많은 기사이기 때문에, 저는 당신이 그를 모셔 가주었으면 좋겠어요."}, {"sp": "W", "en": "Not a problem. Do you know the terminal he's coming into?", "ko": "문제 없어요. 그가 들어오는 터미널 번호를 아세요?"}, {"sp": "M", "en": "Terminal 2. By the way, Lily Street will be shut down this afternoon, so you won't be able to go that way.", "ko": "2번 터미널이에요. 그런데, 오늘 오후에 Lily가가 폐쇄될 예정이라 그 길로 갈 수 없을 거예요."}, {"sp": "W", "en": "Yeah, I heard. But that's fine. There's another route that will also take less than 30 minutes. I'll take that one.", "ko": "네, 들었어요. 하지만 괜찮아요. 30분이 채 걸리지 않는 다른 경로가 있어요. 그 길로 갈게요."}], "gimg": "hk_t3_g65.jpg"}, {"start": 68, "part": 3, "intro": "", "graphic": true, "speakers": "W, M", "audio": "Test03_68-70.mp3", "qs": [{"n": 68, "q": "What is the conversation mainly about?", "opts": ["A consulting fee", "An upcoming meeting", "An urgent report", "A promotional event"], "ans": 1, "ko": "대화는 주로 무엇에 관한 것인가? (A) 컨설팅 요금 (B) 다가오는 회의 (C) 긴급한 보고서 (D) 판촉 행사"}, {"n": 69, "q": "Look at the graphic. When did Delver Group expand overseas?", "opts": ["In February", "In March", "In April", "In May"], "ans": 3, "ko": "시각 자료를 보시오. Delver 그룹은 언제 해외로 확장했는가? (A) 2월에 (B) 3월에 (C) 4월에 (D) 5월에"}, {"n": 70, "q": "What does the woman want to discuss in an e-mail?", "opts": ["Customer feedback", "Business advice", "Expansion locations", "Company policies"], "ans": 1, "ko": "여자는 이메일에서 무엇을 논의하길 원하는가? (A) 고객 의견 (B) 사업 조언 (C) 확장 위치 (D) 회사 정책"}], "script": [{"sp": "W", "en": "I just spoke with the CEO of Delver Group. She wants to hold a meeting with some representatives from our consultancy on Monday. She says it's urgent.", "ko": "저는 방금 Delver 그룹의 최고 경영자와 이야기했어요. 그녀는 월요일에 우리 컨설팅 회사의 몇몇 대표들과 회의를 하고 싶어 해요. 그녀는 이것이 긴급하다고 말했어요."}, {"sp": "M", "en": "Is something wrong?", "ko": "뭔가 잘못되었나요?"}, {"sp": "W", "en": "Sort of. Her company is trying to boost sales in Europe since the firm's profits hit a low for the year during the month when the company expanded overseas.", "ko": "그런 셈이에요. 그녀의 회사가 해외로 확장했던 달 동안 기업의 수익이 올해의 최저점에 이르렀기 때문에 유럽에서의 판매량을 끌어올리려고 하고 있어요."}, {"sp": "M", "en": "I see. Well, I'm free that afternoon. So, let's try to get together with her then.", "ko": "알겠어요. 음, 저는 그날 오후에 한가해요. 그러니 그때 그녀와 만나보도록 해요."}, {"sp": "W", "en": "All right. Beforehand, however, we need to brainstorm business ideas to present to her. I'll send you an e-mail today with what I come up with, and you can respond with your input.", "ko": "좋아요. 하지만 그 전에, 우리는 그녀에게 제시할 사업 방안을 생각해야 해요. 제가 구상하는 것을 오늘 이메일로 당신께 보내드릴 테니, 당신의 의견을 답장으로 보내면 돼요."}], "gimg": "hk_t3_g68.jpg"}, {"start": 71, "part": 4, "intro": "", "graphic": false, "speakers": "W", "audio": "Test03_71-73.mp3", "qs": [{"n": 71, "q": "What is the speaker's occupation?", "opts": ["Government official", "Professional writer", "Real estate agent", "Financial consultant"], "ans": 3, "ko": "화자의 직업은 무엇인가? (A) 공무원 (B) 전문 작가 (C) 부동산 중개인 (D) 재정 상담가"}, {"n": 72, "q": "What will the speaker discuss first?", "opts": ["The risks of some investments", "The goals of a company", "The price of a service", "The benefits of savings accounts"], "ans": 0, "ko": "화자는 처음에 무엇을 논의할 것인가? (A) 투자의 위험 (B) 회사의 목표 (C) 서비스의 가격 (D) 예금 계좌의 혜택"}, {"n": 73, "q": "What does the speaker say she will show listeners?", "opts": ["A brochure", "Some photographs", "A schedule", "Some diagrams"], "ans": 3, "ko": "화자는 청자들에게 무엇을 보여줄 것이라고 말하는가? (A) 소책자 (B) 사진 (C) 일정표 (D) 도표들"}], "script": [{"sp": "W", "en": "My name is Gloria Bloom, and I'm a financial consultant. I'll be leading this seminar, which is being hosted by my firm, Stanley Financial.", "ko": "제 이름은 Gloria Bloom이고, 저는 재정 상담가입니다. 저는 저희 회사인 Stanley Financial사에 의해 주최되는 이 세미나를 이끌 것입니다."}, {"sp": "W", "en": "Our plan for this morning is to discuss ways to improve your personal wealth portfolios.", "ko": "오늘 아침 저희의 계획은 여러분의 개인 재산 포트폴리오를 개선하는 방법을 논의하는 것입니다."}, {"sp": "W", "en": "To start, I'm going to give a short talk about the potential risks of putting money into stocks, government bonds, and real estate.", "ko": "우선, 저는 주식, 국채, 그리고 부동산에 돈을 투자하는 것의 잠재적인 위험성에 관해 간단히 설명할 것입니다."}, {"sp": "W", "en": "Following that, I'll show you a series of charts and graphs that explain which financial products are best suited for short-term gains and why establishing a retirement plan is crucial. All right, let's begin.", "ko": "그다음에, 저는 어떤 금융 상품이 단기 수익에 가장 잘 맞는지와 퇴직자 연금 제도를 설정해 놓은 것이 왜 중요한지 설명하는 일련의 도표들과 그래프들을 보여드릴 것입니다. 좋아요, 이제 시작해보죠."}]}, {"start": 74, "part": 4, "intro": "", "graphic": false, "speakers": "M", "audio": "Test03_74-76.mp3", "qs": [{"n": 74, "q": "Where does the listener work?", "opts": ["At a shipping company", "At a manufacturing plant", "At an electronics store", "At a repair shop"], "ans": 0, "ko": "청자는 어디에서 일하는가? (A) 운송 회사에서 (B) 제조 공장에서 (C) 전자 제품 매장에서 (D) 수리점에서"}, {"n": 75, "q": "What does the speaker say about a television?", "opts": ["It is an incorrect size.", "It was sent to an office.", "It can be customized.", "It has been damaged."], "ans": 3, "ko": "화자는 텔레비전에 관해 무엇을 말하는가? (A) 그것은 맞지 않는 크기이다. (B) 그것은 사무실로 배송되었다. (C) 그것은 주문 제작될 수 있다. (D) 그것은 파손되었다."}, {"n": 76, "q": "What does the speaker mean when he says, \"it is being held this Saturday\"?", "opts": ["A refund does not need to be issued.", "A complaint must be resolved soon.", "A warranty should be extended.", "An event date has been changed."], "ans": 1, "ko": "화자는 \"그것은 이번 주 토요일에 열립니다\"라고 말할 때 무엇을 의도하는가? (A) 환불금을 지급할 필요가 없다. (B) 불만 사항이 빨리 해결되어야 한다. (C) 품질 보증 기간이 연장되어야 한다. (D) 행사 날짜가 변경되었다."}], "script": [{"sp": "M", "en": "My name is Ernesto Agusta. A flat screen television I ordered was sent to my home by your delivery firm.", "ko": "제 이름은 Ernesto Agusta입니다. 제가 주문한 평면 스크린 텔레비전이 당신의 배달 회사에 의해 저희 집으로 배송되었습니다."}, {"sp": "M", "en": "However, the item's box seems to have been torn during transit, leaving a long scratch across the screen.", "ko": "그러나 물품의 상자가 운송 중에 찢어진 것처럼 보이고, 스크린 전체에 걸쳐 긴 긁힌 자국을 남겼습니다."}, {"sp": "M", "en": "I plan to give the item away as a prize during a company event, and it is being held this Saturday.", "ko": "저는 회사 행사 동안에 이 제품을 경품으로 나누어 주려고 계획하고 있고, 그것은 이번 주 토요일에 열립니다."}, {"sp": "M", "en": "Please call me back to let me know your plan for dealing with the matter.", "ko": "이 문제를 처리하는 것에 대한 당신의 계획을 저에게 알려주기 위해 다시 전화 주세요."}]}, {"start": 77, "part": 4, "intro": "", "graphic": false, "speakers": "M-Am", "audio": "Test03_77-79.mp3", "qs": [{"n": 77, "q": "Who are the listeners?", "opts": ["Restaurant investors", "Business owners", "New employees", "Workshop leaders"], "ans": 2, "ko": "청자들은 누구인가?"}, {"n": 78, "q": "What does the speaker ask the listeners to do?", "opts": ["Offer assistance to incoming workers", "Arrange appointments with a supervisor", "Read through a training manual", "Write about a past work experience"], "ans": 3, "ko": "화자는 청자들에게 무엇을 하라고 요청하는가?"}, {"n": 79, "q": "What will probably take place in 15 minutes?", "opts": ["A video screening", "A group discussion", "A registration period", "A lunch break"], "ans": 1, "ko": "15분 후에 무슨 일이 일어날 것 같은가?"}], "script": [{"sp": "M", "en": "Working at a restaurant isn't easy. There are plenty of challenges that you'll face as newly hired staff, from dissatisfied customers to delayed orders to missing ingredients. Such difficulties will be the focus of today's orientation. I would like to start by having everyone write down a challenging situation that you've confronted at a previous job as well as how you managed it. In about 15 minutes, we'll all talk about the experiences as a group and then consider alternative ways that the situations could have been dealt with. OK, let's get started.", "ko": "식당에서 일하는 것은 쉽지 않습니다. 불만스러워하는 고객부터 지연된 주문들, 분실된 재료까지 여러분이 새로 고용된 직원으로서 직면하게 될 많은 도전들이 있습니다. 이러한 어려움들이 오늘 오리엔테이션의 초점이 될 것입니다. 저는 여러분들이 이전 직장에서 직면했던 도전적인 상황과 이를 어떻게 처리했는지에 대해 써보게 함으로써 시작하고 싶습니다. 약 15분 후에, 저희는 모두 그룹으로 모여 경험들에 대해 이야기할 것이고, 그 다음에는 상황을 처리할 수 있었던 대안들을 고려할 것입니다. 자, 그럼 시작합시다."}]}, {"start": 80, "part": 4, "intro": "", "graphic": false, "speakers": "M-Cn", "audio": "Test03_80-82.mp3", "qs": [{"n": 80, "q": "What is the speaker inquiring about?", "opts": ["Whether a client is in town", "How much an upgrade will cost", "If he can use a vehicle", "When a trip will end"], "ans": 2, "ko": "화자는 무엇에 관해 문의하는가?"}, {"n": 81, "q": "Why is the speaker traveling to Portland?", "opts": ["To arrange an event", "To visit a friend", "To attend a conference", "To tour a college campus"], "ans": 1, "ko": "화자는 왜 포틀랜드로 여행하는가?"}, {"n": 82, "q": "What does the speaker ask the listener to do?", "opts": ["Make a decision known", "Contact a rental company", "Return a car before Sunday", "Drive to Portland"], "ans": 0, "ko": "화자는 청자에게 무엇을 하라고 요청하는가?"}], "script": [{"sp": "M", "en": "Jamie, it's Phillip. I have a favor to ask of you. I'm wondering whether I can borrow your car for a trip to Portland next weekend. I'm gonna visit my old college friend, and I'd prefer not to spend money on a rental. If I remember correctly, you'll be in San Diego meeting with a client anyway, so I figure it won't be a major inconvenience for you. I'd need the car from Saturday morning until Sunday afternoon and could return it early that evening. Either way, let me know sometime today in case I need to make other arrangements. I look forward to hearing from you.", "ko": "Jamie, 저 Phillip이에요. 한 가지 부탁할 게 있어요. 제가 다음 주 주말에 포틀랜드로 여행하는 데 당신의 차를 빌릴 수 있는지 궁금해요. 저는 오랜 대학 친구를 방문할 것인데, 차를 대여하는 데 돈을 쓰고 싶지 않아요. 제 기억이 맞다면, 당신은 어차피 샌디에이고에서 고객을 만날 것이니, 이것이 당신에게 크게 불편한 일은 아닐 것이라고 생각해요. 저는 토요일 아침부터 일요일 오후까지 차가 필요하고 그날 이른 저녁에 돌려드릴 수 있어요. 어느 쪽이든, 제가 다른 준비를 해야 할 경우를 대비해서 오늘 중으로 저에게 알려주세요. 연락 기다릴게요."}]}, {"start": 83, "part": 4, "intro": "", "graphic": false, "speakers": "W-Br", "audio": "Test03_83-85.mp3", "qs": [{"n": 83, "q": "What is the announcement mainly about?", "opts": ["A grand opening", "A branch expansion", "A product launch", "A sales event"], "ans": 3, "ko": "공지는 주로 무엇에 관한 것인가?"}, {"n": 84, "q": "What does the speaker suggest customers do?", "opts": ["Become a member", "Purchase a gift card", "Download a flyer", "Check out reviews"], "ans": 0, "ko": "화자는 고객들에게 무엇을 하라고 제안하는가?"}, {"n": 85, "q": "What does the speaker say listeners can do online?", "opts": ["Review recent purchases", "Take advantage of deals", "Read about an upcoming line", "Request product exchanges"], "ans": 1, "ko": "화자는 청자들이 온라인에서 무엇을 할 수 있다고 말하는가?"}], "script": [{"sp": "W", "en": "Attention all Alison Apparel customers. In preparation for our soon-to-be-released winter line, we have decided to mark down everything in the store beginning tomorrow. This includes all remaining shoes, shirts, pants, and dresses from our summer and fall collections. Plus, become a member of our store's rewards program today to receive a complimentary piece of jewelry. These specials will also be offered on our Web site. But you must act quickly! Product availability is limited to what we have in stock.", "ko": "Alison 의류점 고객 분들은 모두 주목해주십시오. 곧 출시될 겨울 제품의 준비로, 저희는 내일부터 상점에 있는 모든 것의 가격을 인하하기로 결정했습니다. 이것은 여름과 가을 컬렉션 중 남아 있는 모든 신발, 셔츠, 바지와 원피스를 포함합니다. 또한, 무료 장신구를 받기 위해 오늘 저희 상점의 보상 프로그램 회원이 되십시오. 이러한 특별 할인가는 저희 웹사이트에서도 제공될 것입니다. 하지만 서두르셔야 합니다! 구매 가능한 제품은 저희가 재고로 보유하고 있는 것에 제한됩니다."}]}, {"start": 86, "part": 4, "intro": "", "graphic": false, "speakers": "M-Am", "audio": "Test03_86-88.mp3", "qs": [{"n": 86, "q": "Where most likely are the listeners?", "opts": ["At a tourist information office", "At a local museum", "At a private residence", "At an art school"], "ans": 3, "ko": "청자들은 어디에 있는 것 같은가?"}, {"n": 87, "q": "Why does the speaker say, \"that stands as a record\"?", "opts": ["To praise an administrator's career", "To explain a business strategy", "To describe a piece of artwork", "To draw attention to a donation"], "ans": 0, "ko": "화자는 왜 \"그것은 기록으로 남아 있습니다\"라고 말하는가?"}, {"n": 88, "q": "What will the listeners probably do next?", "opts": ["Talk with some students", "Head to an auditorium", "Look at an exhibition", "Pay for facility passes"], "ans": 1, "ko": "청자들은 다음에 무엇을 할 것 같은가?"}], "script": [{"sp": "M", "en": "Welcome, everyone, to today's tour of our private school for young, talented artists. There are a lot of things for us to see and discuss, but prior to exploring the facility, we'll first listen to a special lecture from our director, Ronald Marks. Mr. Marks spent nearly 25 years as a director at the nearby Laurel Museum. Over the course of the museum's history, that stands as a record. Now, please follow me down the main hallway to the auditorium, where Mr. Marks is waiting for us. It's a short walk.", "ko": "오늘, 젊고 재능 있는 예술가들을 위한 저희 사립 학교 견학에 오신 여러분을 환영합니다. 저희가 보고 논의할 것들이 많이 있지만, 시설을 답사하기 전에 먼저 저희의 이사장이신 Ronald Marks의 특별 강연을 들을 것입니다. Mr. Marks는 인근의 Laurel 박물관에서 거의 25년을 이사로 보내셨습니다. 박물관의 역사 동안, 그것은 기록으로 남아 있습니다. 이제, Mr. Marks가 기다리고 있는 강당으로 가는 중앙 복도로 저를 따라오시기 바랍니다. 잠깐만 걸으시면 됩니다."}]}, {"start": 89, "part": 4, "intro": "", "graphic": false, "speakers": "W-Au", "audio": "Test03_89-91.mp3", "qs": [{"n": 89, "q": "What does the speaker suggest listeners do?", "opts": ["Try out some running gear", "Raise funds for a registration fee", "Cheer on coworkers", "Stop by a booth"], "ans": 3, "ko": "화자는 청자들에게 무엇을 하라고 제안하는가?"}, {"n": 90, "q": "Why does the speaker feel optimistic?", "opts": ["A lot of people have shown up.", "An additional sponsor was found.", "A weather forecast is favorable.", "An event was well publicized."], "ans": 0, "ko": "화자는 왜 낙관적인가?"}, {"n": 91, "q": "How can listeners receive a sweatshirt?", "opts": ["By buying an admission ticket", "By talking to an event organizer", "By sponsoring a colleague", "By taking part in a race"], "ans": 3, "ko": "청자들은 어떻게 운동복 상의를 받을 수 있는가?"}], "script": [{"sp": "W", "en": "In about half an hour, the Rockton Hospital Charity Day is going to start. If you haven't done so already, you should visit the registration booth, where you can sign up for different races and events. Remember, for every person who takes part in each competition, our sponsors will be donating $75. Seeing as how the turnout this afternoon is much higher than it was last year, I'm hopeful that we'll raise a lot of money. Oh, one more thing. Race participants will be given one of these Rockton Hospital Charity Day sweatshirts at no cost.", "ko": "30분 후에, Rockton 병원 자선의 날이 시작됩니다. 아직 하지 않으셨다면, 여러 가지 경기와 행사에 등록하실 수 있는 접수 부스에 방문하셔야 합니다. 각 대회에 참여하는 각각의 사람들에 대해, 저희 후원 업체가 75달러를 기부할 것임을 기억하십시오. 오늘 오후 참가자의 수가 작년보다 얼마나 더 많은지 보니, 저는 우리가 많은 돈을 모을 수 있을 것이라고 기대합니다. 아, 한 가지 더 있습니다. 경주 참가자들은 Rockton 병원 자선의 날 운동복 상의 중 하나를 무료로 받게 될 것입니다."}]}, {"start": 92, "part": 4, "intro": "", "graphic": false, "speakers": "M-Au", "audio": "Test03_92-94.mp3", "qs": [{"n": 92, "q": "What does the speaker say happened in May?", "opts": ["Some funding was awarded.", "Some focus groups were held.", "A library branch was closed.", "An online database was deleted."], "ans": 0, "ko": "화자는 5월에 무슨 일이 일어났다고 말하는가?"}, {"n": 93, "q": "What does the speaker mean when he says, \"Many people report using them two or three times weekly\"?", "opts": ["Some books have not been returned.", "Complaints have not been addressed.", "A book format is popular.", "An online payment option is convenient."], "ans": 2, "ko": "화자는 \"많은 사람들이 일주일에 두세 번씩 그것을 사용한다고 말합니다\"라고 말할 때 무엇을 의도하는가?"}, {"n": 94, "q": "What are the listeners asked to do?", "opts": ["Sign up for a service", "Conduct some research", "Establish a budget proposal", "Test out a new system"], "ans": 1, "ko": "청자들은 무엇을 하도록 요청받는가?"}], "script": [{"sp": "M", "en": "Our public library plans to modernize its catalog. Specifically, we'll be using some government funding we received in May to expand our online database of audiobooks. More members are interested than ever before in listening to audiobooks during their work commutes. Many people report using them two or three times weekly. In addition, beginning in June, we will place less of an emphasis on acquiring printed books and spend more money on digital versions. What I need you all to do is carry out some research to determine which books are most popular among members, so we can make sure to get copies of them.", "ko": "저희 공립 도서관은 도서 목록을 현대화하려고 계획하고 있습니다. 특히, 저희는 오디오북의 온라인 데이터 베이스를 확장하는 데에 5월에 받은 정부 지원금의 일부를 사용할 것입니다. 그 어느 때보다도 많은 회원들이 통근하는 동안 오디오북 듣는 것에 관심이 있습니다. 많은 사람들이 일주일에 두세 번씩 그것을 사용한다고 말합니다. 게다가 6월부터 저희는 종이 책을 갖추는 것에는 적게 중점을 두고 디지털판을 사는 데 더 많은 돈을 쓸 것입니다. 저는 가장 인기 있는 책의 사본을 확실히 하기 위해 여러분 모두가 회원들 사이에서 어떤 책이 가장 인기 있는지 알아내기 위한 조사를 수행하기를 바랍니다."}]}, {"start": 95, "part": 4, "intro": "", "graphic": true, "speakers": "W-Br", "audio": "Test03_95-97.mp3", "qs": [{"n": 95, "q": "What problem does the speaker mention?", "opts": ["A client was overcharged.", "A sports product must be recalled.", "A shipment was not delivered.", "A message was deleted."], "ans": 2, "ko": "화자는 무슨 문제를 언급하는가?"}, {"n": 96, "q": "Look at the graphic. When was an order placed?", "opts": ["In April", "In May", "In June", "In July"], "ans": 1, "ko": "시각 자료를 보시오. 언제 주문이 들어왔는가?"}, {"n": 97, "q": "What is the speaker waiting for?", "opts": ["Feedback from a sales team", "Permission to carry out a plan", "An order number from staff", "A payment from a customer"], "ans": 1, "ko": "화자는 무엇을 기다리는가?"}], "script": [{"sp": "W", "en": "Mr. Engels, this is Claire Jessup from the customer service department. This message is regarding a recent complaint our distribution center received from a corporate client, Folsum Sports. The retailer ordered some Advent tennis rackets two months ago but failed to receive them. Our records indicate that we didn't have enough stock on hand at the time to fulfill their request for 100 rackets. Consequently, the shipment was supposed to be sent out the next month, but our staff must have forgotten about it. The Folsum employee is rather upset that this issue hasn't been dealt with after so long. I'm planning on giving them a 20 percent discount on this purchase, but I'd like to get approval from you first.", "ko": "Mr. Engels, 저는 고객 서비스 부서의 Claire Jessup입니다. 이 메시지는 저희 유통 센터가 기업 고객인 Folsum 스포츠사로부터 접수한 최근의 불만 사항에 대한 것입니다. 그 소매업체는 두 달 전에 Advent 테니스 라켓 몇 개를 주문했는데 받지 못했습니다. 우리의 기록은 100개의 라켓을 주문한 그들의 요구 사항을 이행하기에 그 당시 충분한 재고를 보유하고 있지 않았다는 것을 보여줍니다. 결과적으로 그 다음 달에 발송이 되었어야 하지만 저희 직원이 그것에 대해 잊어버린 것 같습니다. Folsum사 직원은 이 문제가 이렇게 오랫동안 처리되지 않은 것에 대해 상당히 마음이 상해 있습니다. 저는 그들에게 이번 구매에 대해 20퍼센트 할인을 제공할 계획인데, 당신으로부터 먼저 승인을 받고자 합니다."}], "gimg": "hk_t3_g95.jpg"}, {"start": 98, "part": 4, "intro": "", "graphic": true, "speakers": "Cn", "audio": "Test03_98-100.mp3", "qs": [{"n": 98, "q": "What is being advertised?", "opts": ["A soft drink", "A diet pill", "A pain medicine", "A cleaning liquid"], "ans": 2, "ko": "무엇이 광고되고 있는가?"}, {"n": 99, "q": "Look at the graphic. Which deal is offered for a recently launched bottle?", "opts": ["10% off", "15% off", "20% off", "25% off"], "ans": 3, "ko": "시각 자료를 보시오. 최근에 출시된 병에 관해 어떤 거래가 제공되는가?"}, {"n": 100, "q": "What does the speaker say about CityMart?", "opts": ["It offers free shipping.", "It sells products through a Web site.", "It operates branches nationwide.", "It opened stores in another country."], "ans": 2, "ko": "화자는 CityMart에 관해 무엇을 말하는가?"}], "script": [{"sp": "M", "en": "Do you have a headache that just won't go away? Then try Quick Refresh, a pain relief medication manufactured by SilverEdge Pharmaceuticals. Quick Refresh is scientifically proven to act faster on stubborn headaches than any other medicine on the market. Moreover, Quick Refresh is sold in various bottle sizes, including a recently launched economy-sized bottle for consumers looking to buy in bulk. Our product can be found in CityMart stores across the nation. So, why rely on less effective options? Use fast-acting Quick Refresh!", "ko": "그냥 없어질 것 같지 않은 두통이 있으신가요? 그렇다면 SilverEdge 제약 회사에서 제조한 진통제인 Quick Refresh를 드셔 보세요. Quick Refresh가 시중에 나와 있는 다른 어떤 약보다도 고질적인 두통에 더 빠르게 작용한다는 것이 과학적으로 증명되었습니다. 더욱이, Quick Refresh는 대량으로 구매하기를 원하는 소비자들을 위해 최근에 출시된 절약형 사이즈 병을 포함하여 다양한 병 사이즈로 판매됩니다. 저희 제품은 전국의 CityMart 상점에서 찾으실 수 있습니다. 그러니 왜 덜 효과적인 선택권에 의존하겠습니까? 신속히 효능을 발휘하는 Quick Refresh를 사용하세요!"}], "gimg": "hk_t3_g98.jpg"}]};
